mapper.delete:
delete kbu FROM kb_basic_user kbu
left join kb_basic kb on kbu.b_id = kb.id
where kb.auth = #{auth}
and kbu.b_id = #{basicId}
and kbu.type = 2
and kbu.status = 1

mapper.select:
select count(1) as downloadCount from(
    SELECT DISTINCT b_id from kb_basic_user kbu
    where type = 3 and user_id = #{userId}
    ) t1
